          action="file/upload"
          :limit="3"
          :multiple="true"
          :fileUrls="ruleForm.touxiang?ruleForm.touxiang:''"
          @change="xueshengtouxiangUploadChange"
          ></file-upload>
        </el-form-item>
        <el-form-item class="profile-item" :style='{"width":"50%","margin":"0 0 20px 0"}'   v-if="flag=='xuesheng'"  label="学生手机" prop="xueshengshouji">
          <el-input v-model="ruleForm.xueshengshouji"               placeholder="学生手机" clearable></el-input>
